/**
 * Editable fields for a planned (prescribed) workout. Date, day, week, and phase are immutable - use the swap endpoint to move sessions between days (within the same week or across weeks).
 */
export interface UpdatePlanDayBody {
  sessionType?: string;
  equipment?: string;
  /** Optional ordered chip rail of every machine the runner will use that day. When provided, the server stores it verbatim and (when `equipment` is also patched) validates `equipmentList[0] === equipment`. When omitted but `equipment` changes, the server collapses the rail to `[equipment]`. */
  equipmentList?: string[] | null;
  description?: string;
  distanceMi?: number | null;
  strengthMin?: number | null;
  cardioMin?: number | null;
  runMin?: number | null;
  pace?: string | null;
  strengthLoad?: number | null;
  totalLoad?: number;
  isRest?: boolean;
}

export interface SwapPlanDayBody {
  /** id of the partner plan_day to swap session content with. May be in the same week or in any other week of the plan. */
  withDayId: number;
}

export interface SwapPlanDayResponse {
  from: PlanDay;
  to: PlanDay;
  /** Plan-week numbers whose aggregates were recomputed by this swap. One element for an in-week swap, two for a cross-week swap. */
  weeksAffected: number[];
  /** True when the swap moved sessions across a phase boundary (the two days started out in different phases). */
  phaseChanged: boolean;
  /** Short-lived token for POST /plan/reset/undo to restore the pre-swap state. Expires after roughly 30 seconds. */
  undoToken?: string | null;
  /** Approximate number of seconds the undoToken will remain valid for. Null when undoToken is null. */
  undoExpiresInSeconds?: number | null;
}

export interface ResetPlanWeekResponse {
  week: number;
  /** Number of plan days that actually had a seed snapshot to restore from. Untouched days are not counted. */
  daysReset: number;
  /** Total number of plan days in the week (including untouched ones). */
  daysTotal: number;
  /** Short-lived token that can be passed to POST /plan/reset/undo to restore the just-wiped customizations. Null when nothing was reset (i.e. daysReset is 0). Expires after roughly 30 seconds. */
  undoToken?: string | null;
  /** Approximate number of seconds the undoToken will remain valid for. Null when undoToken is null. */
  undoExpiresInSeconds?: number | null;
}

export interface ResetPlanResponse {
  /** Number of plan_weeks rows wiped by the reset. Zero when the plan tables were already empty. */
  weeksReset: number;
  /** Number of plan_days rows wiped by the reset. Zero when the plan tables were already empty. */
  daysReset: number;
  /** Equal to daysReset (the total number of plan days that existed before the wipe). Kept in the response for OpenAPI back-compat with the prior customization-rollback contract. */
  daysTotal: number;
  /** Short-lived token that can be passed to POST /plan/reset/undo to restore every plan_weeks row, every plan_days row, every previously-applied planner_configs row's applied_*\/last_applied_at columns, and the workouts.plan_day_id FKs that the wipe detached. Null when the plan tables were already empty (i.e. weeksReset and daysReset are both 0). Expires after roughly 30 seconds. */
  undoToken?: string | null;
  /** Approximate number of seconds the undoToken will remain valid for. Null when undoToken is null. */
  undoExpiresInSeconds?: number | null;
}

export interface FullResetPlanResponse {
  /** Number of plan_weeks rows reinserted from the canonical generator (52 for the standard campaign). */
  weeksSeeded: number;
  /** Number of plan_days rows reinserted from the canonical generator (364 for the standard campaign). */
  daysSeeded: number;
  /** Number of logged workout rows that were deleted by the reset. */
  workoutsWiped: number;
  /** Number of measurements rows that were deleted by the reset (includes the baseline row, which is then reinserted from the seed). */
  measurementsWiped: number;
  /** Number of baseline measurements rows reinserted from the seed (1 for the standard campaign). */
  measurementsSeeded: number;
  /** Number of pending reset-undo snapshots that were dropped (so a stale Undo can't restore deleted state after the full reset). */
  undoSnapshotsWiped: number;
}

export interface UndoPlanResetBody {
  /** Token previously returned by POST /plan/weeks/{week}/reset or POST /plan/reset. */
  undoToken: string;
}

export interface UndoPlanResetResponse {
  /** Number of plan days whose pre-reset customizations were restored. */
  daysRestored: number;
  /** Plan-week numbers whose aggregates were recomputed by the undo. */
  weeksAffected: number[];
}

