export type RecompSiteKey = (typeof RecompSiteKey)[keyof typeof RecompSiteKey];

export const RecompSiteKey = {
  belly: "belly",
  chest: "chest",
  arms: "arms",
  legs: "legs",
} as const;

export type RecompSiteSeriesItem = {
  date: string;
  value: number;
};

/**
 * Phase 4. One circumference-tape site in the body-recomp story.
belly/chest are fat-loss sites (shrinking = fat off); arms/legs
are lean-mass PROXY sites (growth there reads as muscle). `delta`
is baseline - latest (positive = the site shrank).

 */
export interface RecompSite {
  key: RecompSiteKey;
  label: string;
  /** True for arms/legs — growth here is treated as a lean-mass proxy. */
  muscleProxy: boolean;
  /** Earliest non-null reading for this site (null if none). */
  baseline: number | null;
  /** Most-recent non-null reading for this site (null if none). */
  latest: number | null;
  /** baseline - latest. Positive = shrank, negative = grew. Null if no reading. */
  delta: number | null;
  /** Chronological non-null date+value points for the per-site sparkline. */
  series: RecompSiteSeriesItem[];
}

/**
 * Phase 4. Server-computed body-recomposition summary. The dashboard
LEADS with "inches lost" + a muscle/strength proxy rather than
weight or races. All fields are guarded for the no-data /
single-measurement case (zeros / nulls, never NaN).

 */
export interface RecompSummary {
  /** Distinct measurement rows. 0 = empty (show the log-first empty), 1 = baseline-only (deltas are 0). */
  measurementCount: number;
  sites: RecompSite[];
  /** Σ of REDUCTIONS (positive baseline-latest) across all four sites. */
  totalInchesLost: number;
  /** Σ of GROWTH (positive latest-baseline) across the arm + leg sites only. */
  muscleProxyInchesGained: number;
  /** Tonal Strength Score, current (entered on Goals). Null until set. */
  strengthScoreCurrent: number | null;
  /** Tonal Strength Score, goal. Null until set. */
  strengthScoreGoal: number | null;
  /** Earliest non-null weight. Weight renders secondary on the new hero. */
  weightBaseline: number | null;
  /** Most-recent non-null weight. */
  weightLatest: number | null;
  /** Combined recomp verdict — inches trending down AND (strength climbing toward goal OR an arm/leg proxy growing). False on empty / single-measurement.
   */
  onTrack: boolean;
}

export interface DashboardSummaryProgram {
  /** Stable identifier for this program within the active planner config (0..N-1). */
  sourceEntryIndex: number;
  /** Human-readable program name (entry.customName or template name); falls back to "Marathon Plan" for legacy single-program campaigns. */
  label: string;
  /** ISO yyyy-mm-dd. Last calendar date this program contributes a plan_day on. Programs in an entries-mode config can finish before the campaign marathonDate (e.g. a 5K Improver block that ends 12 weeks before race day) — this field surfaces that explicitly so the dashboard can show "Tonal Lift ends 2027-01-15" alongside the campaign marathon date.
   */
  endDate: string;
  weeklyMilesPlanned: number;
  /** Sum of `distance_mi` from logged workouts whose plan_day_id links back to one of this program's plan_days in the current week. Workouts that were never linked to a specific plan_day (e.g. unplanned cross-train) only contribute to the combined headline number.
   */
  weeklyMilesActual: number;
  weeklyLoadPlanned: number;
  weeklyLoadActual: number;
  weeklySessionsPlanned: number;
  weeklySessionsCompleted: number;
  /** Task #162. Non-rest plan_days for this program from campaign start through today (inclusive). Drives the per-program adherence slice on the dashboard so a runner stacking a Tonal lift program alongside a 5K running program can spot which program is dragging the combined `adherencePct` down.
   */
  adherencePlanned: number;
  /** Task #162. Subset of `adherencePlanned` for this program that has at least one logged (non-Skipped) workout attributed to it via plan_day_id (or, for legacy workouts with no plan_day_id, a same-date match).
   */
  adherenceCompleted: number;
  /** Task #162. `adherenceCompleted / adherencePlanned * 100`, clamped to [0, 100]. Returns 0 when `adherencePlanned` is 0 (program hasn't started yet).
   */
  adherencePct: number;
}

/**
 * Task #209. Kind of race the campaign is anchored on, derived
from the trailing plan_day Sunday — same detection logic as
`PlanOverview.raceKind` (Task #204) so the dashboard header
and race-week banner stay in lock-step with /plan. Populated
when that final row is a recognised race day (sessionType
`Race` or the generator's "RACE DAY — <Marathon|Half|10K|5K>"
description prefix); resolved from the description first so
a runner who edits the distance still gets the right kind,
then falls back to `distance_mi`. Null on tonal-first /
non-race plans (lift_primary blocks, ad-hoc Custom blocks)
and on legacy / freshly seeded campaigns with no plan_days
yet — the dashboard header keeps generic copy in those cases
so we don't presuppose a race. Drives the "Race Campaign" /
per-kind ("5K Campaign", "10K Campaign", "Half Marathon
Campaign") framing on the dashboard header.

 */
export type DashboardSummaryRaceKind =
  | (typeof DashboardSummaryRaceKind)[keyof typeof DashboardSummaryRaceKind]
  | null;

export const DashboardSummaryRaceKind = {
  marathon: "marathon",
  half: "half",
  "10k": "10k",
  "5k": "5k",
} as const;

export interface DashboardSummary {
  recomp: RecompSummary;
  /** Task #307. False when no Phase Planner config has ever been
applied (fresh installs / after a Full Reset against an empty
`planner_configs`). Drives the dashboard's "Open Phase
Planner" empty state for plan-driven tiles. Body Mass /
Recent Logs / Equipment tiles remain visible even when false.
 */
  hasPlan: boolean;
  currentWeek: number;
  currentPhase: string;
  weekProgressPct: number;
  weeklyMilesActual: number;
  weeklyMilesPlanned: number;
  weeklyLoadActual: number;
  weeklyLoadPlanned: number;
  weeklySessionsCompleted: number;
  weeklySessionsPlanned: number;
  weeklyLifestyleMinutes: number;
  /** Task #34. Average lifestyle minutes per plan_week across the 4 weeks immediately preceding the active plan_week. Null when fewer than 4 prior plan_weeks exist (early-campaign / pre-launch), so the dashboard hides the trend indicator until there is enough history. Used by the Week Snapshot card to show whether the current week's lifestyle minutes are trending up, down, or flat against the runner's recent baseline.
   */
  prevFourWeekAvgLifestyleMinutes: number | null;
  totalMilesAllTime: number;
  longestRunMi: number;
  /** Task #330. Body-mass start target (lbs). Mirrors
`PlanOverview.startWeight` — sourced from the
most-recently-applied planner config's `appliedStartWeight`,
falling back to the runner's earliest measurement weight,
then to null. The Body Mass tile renders an em-dash when
both this and `weightCurrent` are null.
 */
  weightStart: number | null;
  weightCurrent: number | null;
  /** Task #330. Body-mass goal target (lbs). Mirrors
`PlanOverview.goalWeight` — sourced from the
most-recently-applied planner config's `appliedGoalWeight`.
NULL when the runner hasn't set a goal; the Body Mass
tile renders an em-dash sentinel in that case.
 */
  weightGoal: number | null;
  /** (weightStart - weightCurrent), clamped to >= 0. Zero when
either side is null.
 */
  weightLost: number;
  /** (weightCurrent - weightGoal), clamped to >= 0. Zero when
either side is null.
 */
  weightToGoal: number;
  adherencePct: number;
  daysToRace: number;
  /** Task #244. Display name of the currently-active planner
config (mirrors `PlanOverview.activeConfigName`). Drives
the dashboard header title so the runner sees their own
plan name instead of a hardcoded "Half Marathon Campaign".
Falls back to "Workout Plan" when no config has ever been
applied.
 */
  activeConfigName: string;
  /** Task #144. Per-program breakdown of the current week's planned and actual training load for runners stacking concurrent programs (e.g. a Tonal lift program alongside a 5K running program). Each program corresponds to one TemplateEntry currently contributing rows to plan_days. Headline weekly* fields above are the COMBINED totals across all programs; this array lets the dashboard drill in to per-program totals. Always present — for legacy single-program campaigns it contains exactly one element labelled "Marathon Plan". Task #159: programs are ordered by `endDate` ascending (closest race date first), with `sourceEntryIndex` ascending as the tiebreaker, so the most-imminent program surfaces at the top of the Week Snapshot.
   */
  programs: DashboardSummaryProgram[];
  /** Task #209. Kind of race the campaign is anchored on, derived
from the trailing plan_day Sunday — same detection logic as
`PlanOverview.raceKind` (Task #204) so the dashboard header
and race-week banner stay in lock-step with /plan. Populated
when that final row is a recognised race day (sessionType
`Race` or the generator's "RACE DAY — <Marathon|Half|10K|5K>"
description prefix); resolved from the description first so
a runner who edits the distance still gets the right kind,
then falls back to `distance_mi`. Null on tonal-first /
non-race plans (lift_primary blocks, ad-hoc Custom blocks)
and on legacy / freshly seeded campaigns with no plan_days
yet — the dashboard header keeps generic copy in those cases
so we don't presuppose a race. Drives the "Race Campaign" /
per-kind ("5K Campaign", "10K Campaign", "Half Marathon
Campaign") framing on the dashboard header.
 */
  raceKind?: DashboardSummaryRaceKind;
}

