/**
 * Partial update of UserPreferences. Omitted fields are left untouched.
Send maxHr=null or restingHr=null to explicitly clear the configured
value.

 */
export interface UpdateUserPreferencesBody {
  runTargetingMode?: UpdateUserPreferencesBodyRunTargetingMode;
  /**
   * @minimum 80
   * @maximum 230
   */
  maxHr?: number | null;
  /**
   * @minimum 30
   * @maximum 110
   */
  restingHr?: number | null;
  hrZoneModel?: UpdateUserPreferencesBodyHrZoneModel;
  visualTheme?: UpdateUserPreferencesBodyVisualTheme;
  /** IANA timezone string (e.g. "America/Chicago"). Sent by the
client on app load when it detects the browser timezone is
unset or differs from the stored one. Send null to clear.
 */
  timezone?: string | null;
}

/**
 * Result of regenerating plan_weeks and plan_days from the saved Planner config. Workouts and measurements are preserved (not wiped); reset undo snapshots are dropped because their plan_day ids no longer match.
 */
export interface ApplyPlannerConfigResponse {
  weeksSeeded: number;
  daysSeeded: number;
  /** Count of logged workouts that survived the apply (i.e. were not wiped). Their plan_day_id FKs are best-effort re-pointed to the new plan_day with the same date; rows whose date no longer falls within the regenerated plan are kept but get plan_day_id = NULL so the runner doesn't lose history. */
  workoutsPreserved: number;
  measurementsPreserved: number;
  undoSnapshotsWiped: number;
  totalWeeks: number;
}

export interface UpdateAppliedStartingPaceBody {
  /**
   * Runner's starting easy pace in seconds/mile. When this key is
OMITTED, the applied row's existing starting pace is left
untouched (so a runner can patch only the goal anchor
without clobbering their start, and vice versa). Present
with null clears the override, so the generator falls back
to the first block's recipe easy pace (Task #367) — or to
the fixed DEFAULT_STARTING_PACE_SEC when a goal anchor is
set (Task #373). Present with an integer writes it.

   * @minimum 360
   * @maximum 1500
   */
  startingPaceSec?: number | null;
  /**
   * Task #373. Optional goal ending easy pace (sec/mi). When this
key is OMITTED, the applied row's existing goal value is left
untouched (legacy single-field callers stay valid). When
present and non-null, the generator linearly interpolates
from start (week 1) to goal (final week) on the next
backfill. When present and null, the goal anchor is cleared
and the generator reverts to the fixed-rate ramp.

   * @minimum 360
   * @maximum 1500
   */
  goalEndingPaceSec?: number | null;
}

export interface UpdateAppliedStartingPaceResponse {
  /** The newly-applied starting pace (echoes the request value). */
  startingPaceSec: number | null;
  /** Task #373. The currently-applied goal ending pace after the
update. Echoes the request value when the client sent
`goalEndingPaceSec`; otherwise echoes the unchanged
applied-snapshot value so the client always sees the truth
in one round-trip.
 */
  goalEndingPaceSec: number | null;
  /** Run-card plan_days inspected by the backfill. */
  scanned: number;
  /** Run-card rows whose seed_* columns were patched. */
  seedUpdated: number;
  /** Subset of seedUpdated whose runtime columns were also patched (rows the runner had NOT customized through /plan). */
  runtimeUpdated: number;
  /** Rows the runner had customized through /plan — seed patched but runtime preserved. */
  customizedSkipped: number;
  /** Non-run rows skipped by the backfill scope guard. */
  outOfScopeSkipped: number;
}

